package com.lightevents.community;
import jakarta.persistence.*; import jakarta.validation.constraints.NotBlank; import java.time.Instant;
@Entity @Table(name="communities")
public class Community { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @NotBlank private String name; private String slug; @Column(length=2000) private String description; private String city; private String category; private boolean premium; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getName(){return name;} public void setName(String v){name=v;} public String getSlug(){return slug;} public void setSlug(String v){slug=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public String getCity(){return city;} public void setCity(String v){city=v;} public String getCategory(){return category;} public void setCategory(String v){category=v;} public boolean isPremium(){return premium;} public void setPremium(boolean v){premium=v;} public Instant getCreatedAt(){return createdAt;} }
